// ================================================
// STEP 1: VALIDATE & PREPARE LEAD DATA
// ================================================
const input = $input.first().json;
// Support both direct body and nested body (from webhook)
const body = input.body ?? input;

const name    = String(body.name    ?? '').trim();
const email   = String(body.email   ?? '').trim().toLowerCase();
const phone   = String(body.phone   ?? '').trim();
const message = String(body.message ?? '').trim();
const source  = String(body.source  ?? 'Website').trim();

// --- Validation ---
const errors = [];
if (!name)  errors.push('Field name is required');
if (!email) errors.push('Field email is required');
if (email && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
  errors.push('Invalid email format');
}

if (errors.length > 0) {
  return [{ json: { valid: false, errors } }];
}

// --- Split full name into first/last ---
const parts     = name.split(/\s+/);
const firstName = parts[0];
const lastName  = parts.slice(1).join(' ') || '-';

return [{
  json: {
    valid: true,
    firstName,
    lastName,
    fullName: name,
    email,
    phone,
    message,
    source,
    timestamp: new Date().toISOString()
  }
}];

// ================================================
// STEP 2: PREPARE ALL API PAYLOADS
// ================================================
const lead = $('Validate and Prepare').item.json;
const tokenResp = $('Refresh Zoho Token').item.json;
const accessToken = tokenResp.access_token;

if (!accessToken) {
  const errMsg = tokenResp.error || tokenResp.message || JSON.stringify(tokenResp);
  throw new Error(
    `Failed to get access_token from Zoho: ${errMsg}\n` +
    'Check client_id, client_secret, and refresh_token in node "Refresh Zoho Token".'
  );
}

const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;');

const zohoBody = JSON.stringify({
  data: [{
    First_Name: lead.firstName,
    Last_Name: lead.lastName,
    Email: lead.email,
    Phone: lead.phone || '',
    Description: lead.message || '',
    Lead_Source: lead.source || 'Website'
  }]
});

const telegramBody = JSON.stringify({
  chat_id: 'YOUR_TELEGRAM_CHAT_ID',
  parse_mode: 'HTML',
  text:
    '<b>New Lead</b>\n\n' +
    `<b>Name:</b> ${escapeHtml(lead.fullName)}\n` +
    `<b>Email:</b> ${escapeHtml(lead.email)}\n` +
    `<b>Phone:</b> ${escapeHtml(lead.phone || 'N/A')}\n` +
    `<b>Source:</b> ${escapeHtml(lead.source || 'Website')}\n\n` +
    '<b>Message:</b>\n' +
    escapeHtml(lead.message || 'N/A')
});

return [{
  json: {
    lead,
    accessToken,
    zohoBody,
    telegramBody
  }
}];

// ================================================
// STEP 3: ENRICH WITH ZOHO LEAD ID
// ================================================
const payloads = $('Prepare Payload').item.json;
const zohoResp = $input.first().json;

let zohoLeadId = 'N/A';
let zohoStatus = 'unknown';

try {
  const result = Array.isArray(zohoResp.data) ? zohoResp.data[0] : undefined;
  zohoLeadId = result?.details?.id || 'N/A';
  zohoStatus = result?.status || 'unknown';
} catch (error) {}

const telegramPayload = JSON.parse(payloads.telegramBody);
telegramPayload.text += `\n\n<b>Added to Zoho CRM</b>\nID: <code>${zohoLeadId}</code>`;

if (zohoStatus !== 'success') {
  telegramPayload.text += '\n\n<b>Warning:</b> Zoho returned unexpected status: ' + zohoStatus;
}

return [{
  json: {
    ...payloads,
    telegramBodyFinal: JSON.stringify(telegramPayload),
    zohoLeadId,
    zohoStatus,
    zohoResponse: zohoResp
  }
}];
